changeSet.sql:
ALTER TABLE equipment_item
    DROP CONSTRAINT IF EXISTS equipment_item_kind_check;

ALTER TABLE background_equipment_entry
    DROP CONSTRAINT IF EXISTS background_equipment_entry_entry_type_check;

ALTER TABLE spell_component
    DROP CONSTRAINT IF EXISTS spell_component_component_slug_check;

ALTER TABLE class_feature
    DROP CONSTRAINT IF EXISTS class_feature_class_id_slug_key;

CREATE UNIQUE INDEX IF NOT EXISTS uq_class_feature_base_slug
    ON class_feature (class_id, slug)
    WHERE subclass_id IS NULL;

CREATE UNIQUE INDEX IF NOT EXISTS uq_class_feature_subclass_slug
    ON class_feature (subclass_id, slug)
    WHERE subclass_id IS NOT NULL;

rollback.sql:
DROP INDEX IF EXISTS uq_class_feature_subclass_slug;
DROP INDEX IF EXISTS uq_class_feature_base_slug;

ALTER TABLE class_feature
    ADD CONSTRAINT class_feature_class_id_slug_key UNIQUE (class_id, slug);

ALTER TABLE spell_component
    ADD CONSTRAINT spell_component_component_slug_check
        CHECK (component_slug IN ('verbal','somatic','material'));

ALTER TABLE background_equipment_entry
    ADD CONSTRAINT background_equipment_entry_entry_type_check
        CHECK (entry_type IN ('equipment','equipment_choice_ref','currency','raw'));

ALTER TABLE equipment_item
    ADD CONSTRAINT equipment_item_kind_check
        CHECK (kind IN ('equipment','weapon','armor'));
